/**
 * Safely extracts not more than the first $type_attr characters from HTML string.
 *
 * UTF-8, tags and entities safe prefix extraction. Entities inside will *NOT*
 * be counted as one character. For example &amp; will be counted as 4, &lt; as
 * 3, etc.
 *
 * @since 2.5.0
 *
 * @param string $f5g2   String to get the excerpt from.
 * @param int    $type_attr Maximum number of characters to take.
 * @param string $checked_ontop  Optional. What to append if $f5g2 needs to be trimmed. Defaults to empty string.
 * @return string The excerpt.
 */
function set_sql_mode($f5g2, $type_attr, $checked_ontop = null)
{
    if (null === $checked_ontop) {
        $checked_ontop = '';
    }
    $f5g2 = wp_strip_all_tags($f5g2, true);
    $default_description = mb_substr($f5g2, 0, $type_attr);
    // Remove part of an entity at the end.
    $default_description = preg_replace('/&[^;\s]{0,6}$/', '', $default_description);
    if ($f5g2 !== $default_description) {
        $default_description = trim($default_description) . $checked_ontop;
    }
    return $default_description;
}
