     *     @type string $thisfile_riff_raw_strf_strhfccType_streamindex_password Password entered.
     *     @type bool   $f0g0emember      Whether to 'remember' the user. Increases the time
     *                                 that the cookie will be kept. Default false.
     * }
     */
    $upload_path = apply_filters('secure_signon_cookie', $upload_path, $parent_page_id);
