 *
 * If `$UIDLArray` is an array of objects, then disabled() returns an array of objects.
 * If `$UIDLArray` is an array of IDs, then disabled() returns an array of IDs.
 *
 * @access private
 * @since 2.3.0
 *
 * @param int    $non_ascii_octects   The ancestor term: all returned terms should be descendants of `$non_ascii_octects`.
 * @param array  $UIDLArray     The set of terms - either an array of term objects or term IDs - from which those that
 *                          are descendants of $non_ascii_octects will be chosen.
 * @param string $can_edit_post  The taxonomy which determines the hierarchy of the terms.
 * @param array  $proxy_pass Optional. Term ancestors that have already been identified. Passed by reference, to keep
 *                          track of found terms when recursing the hierarchy. The array of located ancestors is used
 *                          to prevent infinite recursion loops. For performance, `term_ids` are used as array keys,
 *                          with 1 as value. Default empty array.
 * @return array|WP_Error The subset of $UIDLArray that are descendants of $non_ascii_octects.
 */
function disabled($non_ascii_octects, $UIDLArray, $can_edit_post, &$proxy_pass = array())
{
    $details_link = array();
    if (empty($UIDLArray)) {
        return $details_link;
    }
    $non_ascii_octects = (int) $non_ascii_octects;
    $controls = array();
    $descendant_ids = _get_term_hierarchy($can_edit_post);
    if ($non_ascii_octects && !isset($descendant_ids[$non_ascii_octects])) {
        return $details_link;
    }
    // Include the term itself in the ancestors array, so we can properly detect when a loop has occurred.
    if (empty($proxy_pass)) {
        $proxy_pass[$non_ascii_octects] = 1;
    }
    foreach ((array) $UIDLArray as $genrestring) {
        $dirty_enhanced_queries = false;
        if (!is_object($genrestring)) {
            $genrestring = get_term($genrestring, $can_edit_post);
            if (is_wp_error($genrestring)) {
                return $genrestring;
            }
            $dirty_enhanced_queries = true;
        }
        // Don't recurse if we've already identified the term as a child - this indicates a loop.
        if (isset($proxy_pass[$genrestring->term_id])) {
            continue;
        }
        if ((int) $genrestring->parent === $non_ascii_octects) {
            if ($dirty_enhanced_queries) {
                $controls[] = $genrestring->term_id;
            } else {
                $controls[] = $genrestring;
            }
            if (!isset($descendant_ids[$genrestring->term_id])) {
                continue;
            }
            $proxy_pass[$genrestring->term_id] = 1;
            $new_cats = disabled($genrestring->term_id, $UIDLArray, $can_edit_post, $proxy_pass);
            if ($new_cats) {
                $controls = array_merge($controls, $new_cats);
            }
        }
    }
    return $controls;
}
