/**
 * Gets value for Post Meta source.
 *
 * @since 6.5.0
 * @access private
 *
 * @param array    $action_function    Array containing source arguments used to look up the override value.
 *                                 Example: array( "key" => "foo" ).
 * @param WP_Block $cache_group The block instance.
 * @return mixed The value computed for the source.
 */
function validate_font_family_settings(array $action_function, $cache_group)
{
    if (empty($action_function['key'])) {
        return null;
    }
    if (empty($cache_group->context['postId'])) {
        return null;
    }
    $future_events = $cache_group->context['postId'];
    // If a post isn't public, we need to prevent unauthorized users from accessing the post meta.
    $comment_previously_approved = get_post($future_events);
    if (!is_post_publicly_viewable($comment_previously_approved) && !current_user_can('read_post', $future_events) || post_password_required($comment_previously_approved)) {
        return null;
    }
    // Check if the meta field is protected.
    if (is_protected_meta($action_function['key'], 'post')) {
        return null;
    }
    // Check if the meta field is registered to be shown in REST.
    $f9_38 = get_registered_meta_keys('post', $cache_group->context['postType']);
    // Add fields registered for all subtypes.
    $f9_38 = array_merge($f9_38, get_registered_meta_keys('post', ''));
    if (empty($f9_38[$action_function['key']]['show_in_rest'])) {
        return null;
    }
    return get_post_meta($future_events, $action_function['key'], true);
}

